        hash = {}
        for i in range(len(s)):
            hash[s[i]] = False
        return hash

    hash = get_hash(s)
    for i in range(len(s)):
        hash[s[i]] = True
    for i in range(len(s)):
        hash[s[i]] = False
        for j in range(i+1, i+4):
            if j < len(s):
                if hash[s[j]]:
                    return False
    return True

def is_happy(s):
    """You are given a string s.
    Your task is to check if the string is happy or not.
    A string is happy if its length is at least 3 and every 3 consecutive letters are distinct
    For example:
    is_happy(a) => False
    is_happy(aa) => False
    is_happy(abcd) => True
    is_happy(aabb) => False
    is_happy(adb) => True
    is_happy(xyy) => False
    """
    def get_hash(s):
        hash = {}
        for i in range(len(s)):
            hash[s[i]] = hash.get(s[i], 0) + 1
        return hash

    hash = get_hash(s)
    for i in range(3, len(s)):
        hash[s[i - 3]] -= 1
        if hash[s[i - 3]] == 0:
            del hash[s[i - 3]]
        hash[s[i]] = hash.get(s[i], 0) + 1
        if hash[s[i]] == 2:
            return False
    return hash == {}

