    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """

    # Initialize the dict
    hist = {}

    # Split string
    split_word = test.split()

    # For each word in the sentence
    for word in split_word:
        # For each letter in the word
        for letter in word:
            # If the letter has not yet occurred, add it to the dict
            if letter not in hist:
                hist[letter] = 1
            # If the letter has occurred, add one to it's value 
            else:
                hist[letter] += 1

    # Return a dictionary with the letter with the highest occurrence
    max_value = max(hist.values())
    max_dict = {}

    for letter, value in hist.items():
